package kotlinx.coroutines.exceptions

import kotlinx.coroutines.*
import org.junit.*
import kotlin.test.*

class NestedExceptionConstructorTest : TestBase() {

    @Test
    fun testNestedExceptionWithCause() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedException, "Expected NestedException but got ${ex::class}")
        assertTrue(ex.cause is IllegalStateException, "Expected IllegalStateException cause but got ${ex.cause?.javaClass}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }

    @Test
    fun testNestedExceptionWithCauseAlternativeOrder() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedExceptionAlternativeOrder(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedExceptionAlternativeOrder, "Expected NestedExceptionAlternativeOrder but got ${ex::class}")
        assertTrue(ex.cause is IllegalStateException, "Expected IllegalStateException cause but got ${ex.cause?.javaClass}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }

    @Test
    fun testNestedExceptionWithMessage() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException("test message")
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedException)
        assertEquals("test message", ex.message)
    }
}

// Constructor order: String, Throwable, no-arg
class NestedException : RuntimeException {
    constructor(message: String) : super(message)
    constructor(cause: Throwable) : super(cause)
    constructor() : super()
}

// Constructor order: Throwable, String, no-arg (alternative order)
class NestedExceptionAlternativeOrder : RuntimeException {
    constructor(cause: Throwable) : super(cause)
    constructor(message: String) : super(message)
    constructor() : super()
}
"}

