package kotlinx.coroutines.exceptions

import kotlinx.coroutines.*
import org.junit.Test
import kotlin.test.*

/**
 * Comprehensive test to verify that constructor selection works correctly
 * regardless of the order constructors are declared.
 */
class ConstructorPriorityTest : TestBase() {

    @Test
    fun testThrowableCausePriorityOverString() = runTest {
        // Verify that constructor(Throwable) is preferred over constructor(String)
        val result = runCatching {
            coroutineScope<Unit> {
                val cause = IllegalStateException("original")
                throw ExceptionWithMultipleConstructors(cause)
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is ExceptionWithMultipleConstructors)
        assertTrue(ex.cause is IllegalStateException)
        assertEquals("original", (ex.cause as IllegalStateException).message)
    }

    @Test
    fun testStringConstructorStillWorks() = runTest {
        // Verify that constructor(String) still works when that's what's used
        val result = runCatching {
            coroutineScope<Unit> {
                throw ExceptionWithMultipleConstructors("test message")
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is ExceptionWithMultipleConstructors)
        assertEquals("test message", ex.message)
    }

    @Test
    fun testNoArgConstructorWorks() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw ExceptionWithMultipleConstructors()
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is ExceptionWithMultipleConstructors)
    }

    @Test
    fun testTwoArgConstructorPreferred() = runTest {
        // When available, constructor(String, Throwable) should be preferred
        val result = runCatching {
            coroutineScope<Unit> {
                val cause = IllegalStateException("cause")
                throw ExceptionWithAllConstructors("message", cause)
            }
